   162→// 1. Helper to parse aspect ratio ("8:10" -> { width: 8, height: 10 })
   163→function parseAspectRatio(aspectRatioStr) {
   164→  const [rawW, rawH] = aspectRatioStr.split(':').map(Number);
   165→  return { width: rawW || 1, height: rawH || 1 };
   166→}
   167→
   168→function generateSizeOptions(aspectRatioStr) {
   169→    // Our list of possible "longest side" lengths:
   170→    const possibleSides = [12, 16, 20, 24, 28, 32];
   171→    // Identify the midpoint index (so if we have 6 items, index=2 => side=20).
   172→    const midpointIndex = Math.floor((possibleSides.length - 1) / 2);
   173→    const defaultSide = possibleSides[midpointIndex];
   174→
   175→    const { width: arW, height: arH } = parseAspectRatio(aspectRatioStr);
   176→    const isLandscape = arW > arH;
   177→    let optionsHtml = '';
   178→
   179→    possibleSides.forEach(side => {
   180→        let finalW, finalH;
   181→        if (isLandscape) {
   182→            // Landscape ratio => width = side, height scaled
   183→            finalW = side;
   184→            finalH = Math.round(arH * (side / arW));
   185→        } else {
   186→            // Portrait / square => height = side, width scaled
   187→            finalH = side;
   188→            finalW = Math.round(arW * (side / arH));
   189→        }
   190→        optionsHtml += `
   191→          <option value="${side}" ${side === defaultSide ? 'selected' : ''}>
   192→            ${finalW}" x ${finalH}" (${side}-${isLandscape ? 'wide' : 'tall'})
   193→          </option>
   194→        `;
   195→    });
   196→
   197→    return optionsHtml;
   198→}
