   418→function initializeBNPLMessaging() {
   419→    if (typeof stripe === 'undefined') {
   420→        console.warn('Stripe not loaded, skipping BNPL messaging');
   421→        return;
   422→    }
   423→    
   424→    try {
   425→        const elements = stripe.elements();
   426→        updateBNPLMessaging(elements);
   427→    } catch (error) {
   428→        console.error('Failed to initialize BNPL messaging:', error);
   429→    }
   430→}
   431→
   432→function updateBNPLMessaging(elements = null) {
   433→    if (typeof stripe === 'undefined') return;
   434→    
   435→    // Get current price for BNPL calculation
   436→    const priceText = document.querySelector('.price').textContent;
   437→    const priceMatch = priceText.match(/\$(\d+(?:\.\d{2})?)/);
   438→    
   439→    if (!priceMatch) {
   440→        console.warn('Could not parse price for BNPL messaging');
   441→        return;
   442→    }
   443→    
   444→    const currentPrice = parseFloat(priceMatch[1]);
   445→    const amountInCents = Math.round(currentPrice * 100);
   446→    
   447→    // Only show BNPL for purchases $50 and above (typical BNPL threshold)
   448→    if (currentPrice < 50) {
   449→        // Hide BNPL messaging for low-value items
   450→        const container = document.getElementById('payment-method-messaging');
   451→        if (container) container.style.display = 'none';
   452→        return;
   453→    }
   454→    
   455→    try {
   456→        // Destroy existing element if it exists
   457→        if (paymentMethodMessaging) {
   458→            paymentMethodMessaging.destroy();
   459→            paymentMethodMessaging = null;
   460→        }
   461→        
   462→        // Create new elements instance if not provided
   463→        if (!elements) {
   464→            elements = stripe.elements();
   465→        }
   466→        
   467→        // Determine user's location/currency preference
   468→        // For now, use USD as base currency with automatic BNPL adaptation
   469→        const options = {
   470→            amount: amountInCents,
   471→            currency: 'USD', // Base currency (prices stored in USD)
   472→            // Let Stripe automatically detect and show appropriate BNPL options
   473→            // based on customer location and currency support
   474→        };
   475→        
   476→        paymentMethodMessaging = elements.create('paymentMethodMessaging', options);
   477→        
   478→        const container = document.getElementById('payment-method-messaging');
   479→        if (container) {
   480→            container.style.display = 'block';
   481→            paymentMethodMessaging.mount('#payment-method-messaging');
   482→            
   483→            // Track BNPL messaging display
   484→            logArtworkInteraction({
   485→                type: 'bnpl_messaging_displayed',
   486→                amount: currentPrice,
   487→                paymentMethods: ['bnpl'] // Will be determined by Stripe based on region
   488→            });
   489→        }
   490→    } catch (error) {
   491→        console.error('Failed to update BNPL messaging:', error);
   492→    }
   493→}
