   507→function calculatePrice(baseSize, selectedSize, isSignedEdition, basePrice, aspectRatioStr) {
   508→    console.log('Calculate price inputs:', { baseSize, selectedSize, isSignedEdition, basePrice, aspectRatioStr });
   509→    const { width: arW, height: arH } = parseAspectRatio(aspectRatioStr);
   510→
   511→    // Decide that "selectedSize" is the longer dimension. For example, if aspect ratio is 8:10
   512→    // we treat "10" as the taller side. So if the user picks 20, we scale so that 10 -> 20,
   513→    // width = 8*(20/10) = 16, height = 20. Then area = 16 * 20 = 320.
   514→    // For 1:1 ratio, it become 20 × 20 = 400, as before.
   515→
   516→    // We'll check if arW < arH (a "portrait" ratio). If so, treat selectedSize as arH. 
   517→    // Otherwise, treat it as arW if arW > arH (a "landscape" ratio).
   518→    let finalW, finalH;
   519→    if (arW > arH) {
   520→        // Landscape ratio
   521→        finalW = selectedSize;
   522→        finalH = Math.round(arH * (selectedSize / arW));
   523→    } else {
   524→        // Portrait or square ratio
   525→        finalH = selectedSize;
   526→        finalW = Math.round(arW * (selectedSize / arH));
   527→    }
   528→    const selectedArea = finalW * finalH;
   529→
   530→    // Compare to base area for a 1:1 ratio with dimension = baseSize
   531→    const baseArea = baseSize * baseSize;
   532→
   533→    // area ratio
   534→    const areaRatio = selectedArea / baseArea;
   535→
   536→    // Take square root of area ratio to dampen the effect
   537→    const dampedRatio = Math.sqrt(areaRatio);
   538→
   539→    // Use the artwork's basePrice
   540→    const price = isSignedEdition ? basePrice : basePrice / 2;
   541→    const finalPrice = Math.round(price * dampedRatio);
   542→    console.log('Calculated price:', finalPrice, 'selectedArea:', selectedArea);
   543→    return { finalPrice, finalW, finalH };
   544→}
