   553→
   554→    const size = parseInt(sizeSelect.value);
   555→    const isSignedEdition = editionSelect.value === 'signed';
   556→    const quantity = parseInt(quantityInput.value) || 1;
   557→
   558→    // 3. Adapt the call so it returns the computed width/height as well
   559→    const { finalPrice, finalW, finalH } = calculatePrice(20, size, isSignedEdition, basePrice, aspectRatioStr);
   560→    const totalPrice = finalPrice * quantity;
   561→
   562→    // Use currency manager for proper formatting if available
   563→    const priceElement = document.querySelector('.price');
   564→    if (window.currencyManager) {
   565→        priceElement.textContent = window.currencyManager.formatPrice(totalPrice);
   566→        priceElement.dataset.usdPrice = totalPrice; // Store USD price for reference
