   580→    if (totalPrice >= 50) { // Only show BNPL for $50+
   581→        if (window.currencyManager) {
   582→            bnplElement.innerHTML = `<em>or acquire in 4 interest-free installments of ${window.currencyManager.formatPrice(installmentAmount)}</em>`;
   583→        } else {
