   591→    // 4. Update the displayed "Actual Dimensions" text
   592→    const dimsElem = document.getElementById('computed-dimensions');
   593→    if (dimsElem) {
   594→        dimsElem.textContent = `${finalW}" x ${finalH}" per print`;
