   740→// Enhanced algorithm to find related artworks using CLIP similarity
   741→function getRelatedArtworks(currentArtwork, allArtworks, maxResults = 3) {
   742→    // Try CLIP-based recommendations first
   743→    if (clipSimilarityService.isReady()) {
   744→        console.log('Using CLIP-based similarity for related artworks');
   745→        
   746→        const clipRecommendations = clipSimilarityService.getHybridRecommendations(
