   764→                similarityMethod: 'clip_hybrid'
   765→            });
   766→            
   767→            return clipRecommendations;
   768→        }
   769→    }
   770→    
   771→    // Fallback to original algorithm if CLIP data not available
   772→    console.log('Using traditional similarity algorithm (fallback)');
   773→    
   774→    const related = [];
   775→    
   776→    // 1. First priority: Same collection (excluding current artwork)
   777→    const sameCollection = allArtworks.filter(artwork => 
   778→        artwork.collection === currentArtwork.collection && 
   779→        artwork.id !== currentArtwork.id
   780→    );
   781→    
   782→    // Add up to 2 artworks from same collection
   783→    related.push(...sameCollection.slice(0, 2));
   784→    
   785→    // 2. Second priority: Featured artworks from different collections
   786→    if (related.length < maxResults) {
   787→        const featuredOthers = allArtworks.filter(artwork => 
   788→            artwork.isFeatured && 
   789→            artwork.collection !== currentArtwork.collection &&
   790→            !related.some(r => r.id === artwork.id)
   791→        );
   792→        
   793→        const needed = maxResults - related.length;
   794→        related.push(...featuredOthers.slice(0, needed));
   795→    }
   796→    
   797→    // 3. Fallback: Random selection from different collections
   798→    if (related.length < maxResults) {
   799→        const others = allArtworks.filter(artwork => 
   800→            artwork.collection !== currentArtwork.collection &&
   801→            !related.some(r => r.id === artwork.id)
   802→        );
   803→        
   804→        // Shuffle and take what we need
   805→        const shuffled = others.sort(() => Math.random() - 0.5);
   806→        const needed = maxResults - related.length;
   807→        related.push(...shuffled.slice(0, needed));
   808→    }
   809→    
   810→    // Track analytics for traditional recommendations
   811→    logArtworkInteraction({
   812→        type: 'traditional_recommendations_used',
   813→        artworkId: currentArtwork.id,
   814→        recommendationCount: related.length,
   815→        similarityMethod: 'collection_based'
   816→    });
   817→    
   818→    return related.slice(0, maxResults);
   819→}
