const securityHeaders = {
    'Access-Control-Allow-Origin': process.env.URL || 'https://www.edmunddantesstudio.com',
    'Access-Control-Allow-Methods': 'POST, OPTIONS',
    'Access-Control-Allow-Headers': 'Content-Type',
    'Access-Control-Max-Age': '86400',
    'X-Content-Type-Options': 'nosniff',
    'X-Frame-Options': 'DENY',
    'X-XSS-Protection': '1; mode=block'
};

// Cache exchange rates for 1 hour to avoid hitting rate limits
let cachedRates = null;
let cacheTimestamp = 0;
const CACHE_DURATION = 60 * 60 * 1000; // 1 hour in milliseconds

export const handler = async (event) => {
    // Handle preflight CORS requests
    if (event.httpMethod === 'OPTIONS') {
        return {
            statusCode: 200,
            headers: securityHeaders,
            body: ''
        };
    }

    if (event.httpMethod !== 'POST') {
        return {
            statusCode: 405,
            headers: securityHeaders,
            body: JSON.stringify({ error: 'Method not allowed' })
        };
    }

    try {
        const { currency } = JSON.parse(event.body);

        if (!currency || currency === 'USD') {
            return {
                statusCode: 200,
                headers: {
                    ...securityHeaders,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    success: true,
                    rates: { USD: 1 }, // No conversion needed for USD
                    base: 'USD',
                    timestamp: Date.now()
                })
            };
        }

        // Check cache first
        const now = Date.now();
        if (cachedRates && (now - cacheTimestamp) < CACHE_DURATION) {
            console.log('Returning cached exchange rates');
            return {
                statusCode: 200,
                headers: {
                    ...securityHeaders,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    success: true,
                    rates: cachedRates,
                    base: 'USD',
                    timestamp: cacheTimestamp,
                    cached: true
                })
            };
        }

        // For now, use Stripe's approach: simple static rates for common currencies
        // In production, you'd want to use a proper exchange rate API
        const staticRates = {
            'USD': 1.0,
            'CAD': 1.35,  // Approximate CAD/USD rate
            'EUR': 0.85,  // Approximate EUR/USD rate
            'GBP': 0.75,  // Approximate GBP/USD rate
            'AUD': 1.50,  // Approximate AUD/USD rate
            'JPY': 110.0, // Approximate JPY/USD rate
            'CHF': 0.90,  // Approximate CHF/USD rate
            'SEK': 10.5,  // Approximate SEK/USD rate
            'NOK': 10.8,  // Approximate NOK/USD rate
            'DKK': 6.3    // Approximate DKK/USD rate
        };

        // Try to fetch live rates from a free API (with fallback to static rates)
        let rates = staticRates;

        try {
            // Using exchangerate-api.com (free tier: 1500 requests/month)
            const response = await fetch(`https://api.exchangerate-api.com/v4/latest/USD`);
            if (response.ok) {
                const data = await response.json();
                if (data.rates) {
                    rates = { USD: 1, ...data.rates };
                    console.log('Fetched live exchange rates');
                }
            }
        } catch (error) {
            console.warn('Could not fetch live rates, using static rates:', error.message);
        }

        // Cache the rates
        cachedRates = rates;
        cacheTimestamp = now;

        return {
            statusCode: 200,
            headers: {
                ...securityHeaders,
                'Content-Type': 'application/json'
            },
            body: JSON.stringify({
                success: true,
                rates: rates,
                base: 'USD',
                timestamp: now,
                requestedCurrency: currency
            })
        };

    } catch (error) {
        console.error('Exchange rate fetch error:', error);

        return {
            statusCode: 500,
            headers: {
                ...securityHeaders,
                'Content-Type': 'application/json'
            },
            body: JSON.stringify({
                success: false,
                error: 'Failed to fetch exchange rates'
            })
        };
    }
};

