import Stripe from 'stripe';

const stripe = new Stripe(process.env.STRIPE_SECRET_KEY);

// In-memory cache for exchange rates
// In production, consider using Netlify Blobs or Redis
let ratesCache = {
    data: null,
    timestamp: 0
};

// Cache for 4 hours (Stripe updates rates hourly)
const CACHE_TTL_MS = 4 * 60 * 60 * 1000;

/**
 * Get exchange rates from Stripe with caching
 * Returns rates object where keys are lowercase currency codes
 * and values are exchange rates from USD
 */
export async function getExchangeRates() {
    const now = Date.now();

    // Return cached rates if still valid
    if (ratesCache.data && (now - ratesCache.timestamp) < CACHE_TTL_MS) {
        console.log('Using cached exchange rates');
        return ratesCache.data;
    }

    // Check if we're in test mode
    const isTestMode = process.env.STRIPE_SECRET_KEY && process.env.STRIPE_SECRET_KEY.startsWith('sk_test_');

    if (isTestMode) {
        console.log('Using static exchange rates for test mode (Stripe Exchange Rates API requires live mode)');
        // Return realistic test rates
        // These are approximate rates as of 2024
        ratesCache = {
            data: {
                usd: 1.0,
                eur: 0.92,
                gbp: 0.79,
                cad: 1.35,
                aud: 1.52,
                jpy: 149.50,
                chf: 0.88,
                sek: 10.47,
                nok: 10.64,
                dkk: 6.84,
                nzd: 1.63,
                sgd: 1.34,
                hkd: 7.82,
                mxn: 17.15,
                brl: 4.97,
                inr: 83.12,
                cny: 7.20,
                krw: 1318.52,
                thb: 35.47,
                myr: 4.67,
                idr: 15650,
                php: 55.89,
                pln: 3.98,
                czk: 22.61,
                huf: 352.87,
                ron: 4.57,
                bgn: 1.80,
                hrk: 6.93,
                rub: 91.35,
                try: 32.15,
                zar: 18.76,
                ils: 3.71,
                aed: 3.67,
                sar: 3.75,
                egp: 30.90
            },
            timestamp: now
        };
        return ratesCache.data;
    }

    try {
        console.log('Fetching fresh exchange rates from Stripe (live mode)');

        // Check if Stripe is properly initialized
        if (!stripe) {
            throw new Error('Stripe not initialized in exchange-rates module');
        }

        const exchangeRates = await stripe.exchangeRates.retrieve('usd');

        // Validate the response
        if (!exchangeRates || !exchangeRates.rates) {
            throw new Error('Invalid exchange rates response from Stripe');
        }

        // Stripe returns rates as an object with lowercase currency codes
        ratesCache = {
            data: exchangeRates.rates,
            timestamp: now
        };

        console.log('Exchange rates updated:', Object.keys(ratesCache.data).length, 'currencies');
        return ratesCache.data;
    } catch (error) {
        console.error('Failed to fetch exchange rates:', {
            message: error.message,
            type: error.type,
            code: error.code
        });

        // If we have stale cache, use it as fallback
        if (ratesCache.data) {
            console.warn('Using stale exchange rates as fallback');
            return ratesCache.data;
        }

        // This shouldn't happen in live mode, but provide fallback
        console.error('Using emergency fallback rates');
        return {
            usd: 1.0,
            eur: 0.92,
            gbp: 0.79,
            cad: 1.35,
            aud: 1.52
        };
    }
}

/**
 * Convert USD amount to target currency
 * @param {number} amountUSD - Amount in USD (in dollars, not cents)
 * @param {string} targetCurrency - Target currency code (e.g., 'EUR')
 * @returns {number} Amount in target currency (in smallest unit, e.g., cents)
 */
export async function convertUSDToTargetCurrency(amountUSD, targetCurrency) {
    const currency = targetCurrency.toLowerCase();

    // No conversion needed for USD
    if (currency === 'usd') {
        return Math.round(amountUSD * 100);
    }

    const rates = await getExchangeRates();
    const rate = rates[currency];

    if (!rate) {
        throw new Error(`Exchange rate not found for currency: ${targetCurrency}`);
    }

    // Convert to target currency and round to avoid floating point issues
    const amountInTargetCurrency = amountUSD * rate;

    // Handle zero-decimal currencies (JPY, KRW, etc.)
    const zeroDecimalCurrencies = ['bif', 'clp', 'djf', 'gnf', 'jpy', 'kmf', 'krw', 
                                   'mga', 'pyg', 'rwf', 'ugx', 'vnd', 'vuv', 'xaf', 
                                   'xof', 'xpf'];

    if (zeroDecimalCurrencies.includes(currency)) {
        return Math.round(amountInTargetCurrency);
    }

    // Standard currencies (2 decimal places)
    return Math.round(amountInTargetCurrency * 100);
}

/**
 * Format amount for display (handles decimal places correctly)
 * @param {number} amountInSmallestUnit - Amount in smallest unit (cents, etc.)
 * @param {string} currency - Currency code
 * @returns {string} Formatted amount
 */
export function formatCurrencyAmount(amountInSmallestUnit, currency) {
    const curr = currency.toLowerCase();

    // Zero-decimal currencies
    const zeroDecimalCurrencies = ['bif', 'clp', 'djf', 'gnf', 'jpy', 'kmf', 'krw', 
                                   'mga', 'pyg', 'rwf', 'ugx', 'vnd', 'vuv', 'xaf', 
                                   'xof', 'xpf'];

    if (zeroDecimalCurrencies.includes(curr)) {
        return amountInSmallestUnit.toString();
    }

    // Three-decimal currencies (rare but important)
    const threeDecimalCurrencies = ['bhd', 'jod', 'kwd', 'omr', 'tnd'];

    if (threeDecimalCurrencies.includes(curr)) {
        return (amountInSmallestUnit / 1000).toFixed(3);
    }

    // Standard two-decimal currencies
    return (amountInSmallestUnit / 100).toFixed(2);
}

