// Pinterest Integration Functions
function updatePinterestMetadata(artwork) {
    const urlParams = new URLSearchParams(window.location.search);
    const artworkId = urlParams.get('id');
    const pageUrl = window.location.href;
    const imageUrl = new URL(artwork.src, window.location.origin).href;
    const title = `${artwork.title} | Edmund Dantes Studio`;
    const description = `${artwork.description || artwork.title} - Original geometric art print by Edmund Dantes Studio. Perfect for modern homes and offices. #geometricart #modernart #walldecor`;
    const price = artwork.basePrice || artwork.price || 350;
    const dynamicAltText = `A close-up of '${artwork.title}', an abstract artwork by Edmund Dantes Studio.`;

    // Update Open Graph meta tags
    updateMetaTag('property', 'og:title', title);
    updateMetaTag('property', 'og:description', description);
    updateMetaTag('property', 'og:url', pageUrl);
    updateMetaTag('property', 'og:image', imageUrl);
    updateMetaTag('property', 'og:image:alt', dynamicAltText);

    // Update product-specific meta tags
    updateMetaTag('property', 'product:price:amount', price.toString());
    updateMetaTag('property', 'product:retailer_item_id', artworkId);

    // Update Twitter Card meta tags
    updateMetaTag('name', 'twitter:title', title);
    updateMetaTag('name', 'twitter:description', description);
    updateMetaTag('name', 'twitter:image', imageUrl);
    updateMetaTag('name', 'twitter:image:alt', dynamicAltText);

    // Update page title
    document.title = title;

    // Update canonical URL
    updateMetaTag('rel', 'canonical', pageUrl, 'link');

    // Update Schema.org structured data
    updateProductSchema(artwork, artworkId, pageUrl, imageUrl, price);

    console.log('✓ Pinterest metadata updated for:', artwork.title);
}

function updateMetaTag(attribute, value, content, tagType = 'meta') {
    let element = document.querySelector(`${tagType}[${attribute}="${value}"]`);

    if (!element) {
        element = document.createElement(tagType);
        element.setAttribute(attribute, value);
        document.head.appendChild(element);
    }

    if (tagType === 'link') {
        element.setAttribute('href', content);
    } else {
        element.setAttribute('content', content);
    }
}

function updateProductSchema(artwork, artworkId, pageUrl, imageUrl, price) {
    const schemaElement = document.getElementById('product-schema');
    if (!schemaElement) return;

    const schema = {
        "@context": "https://schema.org",
        "@type": "Product",
        "name": artwork.title,
        "image": [imageUrl],
        "description": artwork.description || `${artwork.title} - Original geometric art print`,
        "sku": artworkId,
        "brand": {
            "@type": "Brand",
            "name": "Edmund Dantes Studio"
        },
        "offers": {
            "@type": "Offer",
            "url": pageUrl,
            "priceCurrency": "USD",
            "price": price.toString(),
            "availability": "https://schema.org/InStock",
            "seller": {
                "@type": "Organization",
                "name": "Edmund Dantes Studio"
            }
        },
        "category": "Art & Wall Decor",
        "audience": {
            "@type": "Audience",
            "audienceType": "Art Collectors, Interior Designers, Home Decorators"
        }
    };

    schemaElement.textContent = JSON.stringify(schema, null, 2);
}

