// Initialize cart from localStorage
let cartItems = JSON.parse(localStorage.getItem('cartItems')) || [];

// Get DOM elements - add conditional checks
const cartToggle = document.getElementById('cart-toggle');
const shoppingCart = document.getElementById('shopping-cart');
const checkoutButton = document.getElementById('checkout-button');

// Consolidate all cart-related event listeners in one place
document.addEventListener('DOMContentLoaded', () => {
    // Clear any failed analytics interactions that might interfere
    try {
        const failedInteractions = localStorage.getItem('failedInteractions');
        if (failedInteractions) {
            console.log('Clearing failed analytics interactions');
            localStorage.removeItem('failedInteractions');
        }
    } catch (e) {
        console.warn('Could not clear failed interactions:', e);
    }

    const cartToggle = document.getElementById('cart-toggle');
    const shoppingCart = document.getElementById('shopping-cart');
    const closeCart = document.querySelector('.close-cart');

    // Cart toggle functionality
    if (cartToggle && shoppingCart) {
        cartToggle.addEventListener('click', (e) => {
            e.preventDefault(); // Prevent any default behavior
            e.stopPropagation(); // Prevent event bubbling
            shoppingCart.classList.toggle('active');
            console.log('Cart toggled'); // Debug log
        });
    }

    // Close cart functionality
    if (closeCart && shoppingCart) {
        closeCart.addEventListener('click', () => {
            shoppingCart.classList.remove('active');
        });
    }

    // Close cart when clicking outside
    document.addEventListener('click', (e) => {
        // If the click originates from the open-checkout-sidebar button, do nothing
        if (e.target.closest('#open-checkout-sidebar')) return;

        if (shoppingCart && shoppingCart.classList.contains('active')) {
            // If the shopping cart has 'data-keep-open', skip closing it
            if (shoppingCart.hasAttribute('data-keep-open')) return;

            if (!shoppingCart.contains(e.target) && e.target !== cartToggle) {
                shoppingCart.classList.remove('active');
            }
        }
    });

    // Initialize cart display
    updateCartDisplay();
});

// Add to cart function
function addToCart(item) {
    // Ensure required properties exist
    if (!item.id || !item.title || !item.price) {
        console.error('Invalid item data:', item);
        return;
    }

    // Convert quantity to number
    item.quantity = parseInt(item.quantity) || 1;

    // Store original price but don't modify it
    // Server will handle all pricing calculations
    item.originalPrice = item.price;

    // Flag for Instagram discount eligibility (server will validate)
    const isInstagramTraffic = sessionStorage.getItem('instagramPricing') === 'true';
    if (isInstagramTraffic) {
        item.eligibleForInstagramDiscount = true;
    }

    // Calculate display price for UI (actual price determined by server)
    item.totalPrice = item.price * item.quantity;

    cartItems.push(item);
    localStorage.setItem('cartItems', JSON.stringify(cartItems));
    updateCartDisplay();

    // Show feedback
    const cartElement = document.getElementById('shopping-cart');
    if (cartElement) {
        cartElement.classList.add('active');
    }
}

function removeFromCart(itemId) {
    cartItems = cartItems.filter(item => item.id !== itemId);
    localStorage.setItem('cartItems', JSON.stringify(cartItems));
    updateCartDisplay();
}

function updateCartDisplay() {
    const cartCount = document.querySelector('.cart-count');
    if (cartCount) {
        cartCount.textContent = cartItems.length;
    }

    const cartItemsContainer = document.getElementById('cart-items');
    if (cartItemsContainer) {
        // Clear existing content safely
        cartItemsContainer.textContent = '';

        // Create cart items using safe DOM manipulation
        cartItems.forEach(item => {
            const cartItemDiv = document.createElement('div');
            cartItemDiv.className = 'cart-item';

            // Create and append image
            const img = document.createElement('img');
            img.src = item.src;
            img.alt = item.title;
            cartItemDiv.appendChild(img);

            // Create details container
            const detailsDiv = document.createElement('div');
            detailsDiv.className = 'cart-item-details';

            // Create and append title
            const title = document.createElement('h4');
            title.textContent = item.title;
            detailsDiv.appendChild(title);

            // Create and append size
            const size = document.createElement('p');
            size.textContent = `Size: ${item.size}cm x ${item.size}cm`;
            detailsDiv.appendChild(size);

            // Create and append frame
            const frame = document.createElement('p');
            frame.textContent = `Frame: ${item.frame}`;
            detailsDiv.appendChild(frame);

            // Create and append quantity
            const quantity = document.createElement('p');
            quantity.textContent = `Quantity: ${item.quantity}`;
            detailsDiv.appendChild(quantity);

            // Create and append price with currency formatting
            const price = document.createElement('p');
            if (window.currencyManager) {
                price.textContent = window.currencyManager.formatPrice(item.totalPrice);
            } else {
                price.textContent = `$${item.totalPrice.toFixed(2)} USD`;
            }
            detailsDiv.appendChild(price);

            cartItemDiv.appendChild(detailsDiv);

            // Create remove button with secure event listener
            const removeButton = document.createElement('button');
            removeButton.textContent = '×';
            removeButton.addEventListener('click', () => removeFromCart(item.id));
            cartItemDiv.appendChild(removeButton);

            cartItemsContainer.appendChild(cartItemDiv);
        });
    }

    updateCartTotal();
}

function updateCartTotal() {
    const total = cartItems.reduce((sum, item) => sum + item.totalPrice, 0);
    const cartTotalElement = document.getElementById('cart-total');
    if (cartTotalElement) {
        if (window.currencyManager) {
            // Use full formatted price with currency symbol
            cartTotalElement.textContent = window.currencyManager.formatPrice(total);
        } else {
            cartTotalElement.textContent = `$${total.toFixed(2)} USD`;
        }
    }
}

function validateCart() {
    if (!cartItems || cartItems.length === 0) return false;

    return cartItems.every(item => 
        item.id && 
        typeof item.id === 'string' &&
        item.price && 
        !isNaN(parseFloat(item.price)) &&
        item.quantity && 
        Number.isInteger(parseInt(item.quantity)) &&
        item.title &&
        typeof item.title === 'string' &&
        item.size &&
        !isNaN(parseFloat(item.size))
    );
}

// At the top of your cart.js file
async function validateStripeSetup() {
    try {
        const response = await fetch('/.netlify/functions/debug-stripe');
        const data = await response.json();
        console.log('Stripe setup check:', data);

        if (!stripe) {
            console.error('Stripe not initialized');
            return false;
        }

        return true;
    } catch (error) {
        console.error('Stripe validation failed:', error);
        return false;
    }
}

// Update the checkout function
async function checkout() {
    // Check cart has items first
    const liveCart = JSON.parse(localStorage.getItem('cartItems')) || [];

    if (liveCart.length === 0) {
        alert('Your cart is empty. Please add items before checking out.');
        return;
    }

    const isValid = await validateStripeSetup();
    if (!isValid) {
        alert('Payment system not properly initialized. Please try again later.');
        return;
    }

    try {
        const button = document.getElementById('checkout-button');
        if (button) button.classList.add('is-loading');

        console.log('Creating checkout session...');
        // Check for Instagram discount eligibility
        const isInstagramTraffic = sessionStorage.getItem('instagramPricing') === 'true';

        const response = await fetch('/.netlify/functions/create-checkout', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ 
                // Send only secure identifiers - server determines pricing
                items: cartItems.map(item => ({
                    id: item.id,
                    quantity: parseInt(item.quantity),
                    // Don't send price - server will look it up
                })),
                // Server will validate this claim
                requestInstagramDiscount: isInstagramTraffic,
                // Analytics context for server validation
                sessionId: sessionStorage.getItem('sessionId'),
                trafficSource: JSON.parse(sessionStorage.getItem('trafficSource') || '{}'),
                // Send current page URL so user returns here on cancel
                referrerUrl: window.location.href
            })
        });

        const responseData = await response.json();
        console.log('Checkout response:', {
            ok: response.ok,
            status: response.status,
            data: responseData
        });

        if (!response.ok) {
            throw new Error(responseData.error || 'Checkout failed');
        }

        const { sessionId, currency, detectedCountry } = responseData;
        console.log('Redirecting to checkout:', {
            sessionId,
            currency,
            detectedCountry
        });

        const { error } = await stripe.redirectToCheckout({ sessionId });
        if (error) {
            console.error('Redirect error:', error);
            throw error;
        }
    } catch (error) {
        console.error('Checkout error:', error);
        alert('There was a problem with checkout. Please try again.');
    } finally {
        const button = document.getElementById('checkout-button');
        if (button) button.classList.remove('is-loading');
    }
}
// Update checkout button listener - only if on cart page
if (checkoutButton) {
    checkoutButton.addEventListener('click', () => {
        console.log('Checkout button clicked');
        checkout();
    });
}

// Make updateCartDisplay globally available for currency manager
window.updateCartDisplay = updateCartDisplay;

