// Helper function to parse aspect ratio
function parseAspectRatio(aspectRatioStr) {
    const [rawW, rawH] = aspectRatioStr.split(':').map(Number);
    return { width: rawW || 1, height: rawH || 1 };
}

// Server-side price calculation - must match frontend logic exactly
function calculatePrice(baseSize, selectedSize, isSignedEdition, basePrice, aspectRatioStr) {
    const { width: arW, height: arH } = parseAspectRatio(aspectRatioStr);

    // Calculate dimensions based on longest side
    let finalW, finalH;
    if (arW > arH) {
        // Landscape ratio
        finalW = selectedSize;
        finalH = Math.round(arH * (selectedSize / arW));
    } else {
        // Portrait or square ratio
        finalH = selectedSize;
        finalW = Math.round(arW * (selectedSize / arH));
    }

    const selectedArea = finalW * finalH;
    const baseArea = baseSize * baseSize;
    const areaRatio = selectedArea / baseArea;
    const dampedRatio = Math.sqrt(areaRatio);

    // Apply edition pricing
    const price = isSignedEdition ? basePrice : basePrice / 2;
    const finalPrice = Math.round(price * dampedRatio);

    return { finalPrice, finalW, finalH };
}

