    /**
     * Check if currency code is valid
     */
    isValidCurrency(currency) {
        const validCurrencies = [
            'USD', 'CAD', 'EUR', 'GBP', 'AUD', 'JPY', 'CHF', 'SEK', 'NOK', 'DKK',
            'PLN', 'CZK', 'HUF', 'RON', 'BGN', 'HRK', 'RUB', 'TRY', 'BRL', 'MXN'
        ];
        return validCurrencies.includes(currency.toUpperCase());
    }

    /**
     * Set user currency (for currency switcher)
     */
    async setUserCurrency(currency) {
        if (!this.isValidCurrency(currency)) {
            console.error('Invalid currency:', currency);
            return false;
        }

        this.userCurrency = currency.toUpperCase();
        localStorage.setItem('userCurrency', this.userCurrency);

        // Load new exchange rates if needed
        if (this.userCurrency !== 'USD') {
            await this.loadExchangeRates();
        } else {
            this.exchangeRates = null;
        }

        // Update all prices on the page
        this.updateAllPrices();

        // Update cart display if cart is visible
        this.updateCartDisplay();

        console.log('💰 Currency changed to:', this.userCurrency);
        return true;
    }

    /**
     * Get current user currency
     */
    getUserCurrency() {
        return this.userCurrency;
    }

    /**
     * Get currency symbol
     */
    getCurrencySymbol() {
        return this.fallbackSymbols[this.userCurrency] || this.userCurrency + ' ';
    }
}

