/**
 * Frontend Currency Display Module
 * Handles currency detection, conversion, and display for the frontend
 */

class CurrencyDisplayManager {
    constructor() {
        this.userCurrency = 'USD';
        this.exchangeRates = null;
        this.isLoading = false;
        this.fallbackSymbols = {
            'USD': '$',
            'CAD': 'C$',
            'EUR': '€',
            'GBP': '£',
            'AUD': 'A$',
            'JPY': '¥',
            'CHF': 'Fr',
            'SEK': 'kr',
            'NOK': 'kr',
            'DKK': 'kr'
        };

        this.init();
    }

    async init() {
        // Detect user's currency from various sources
        await this.detectUserCurrency();

        // Load exchange rates if not USD
        if (this.userCurrency !== 'USD') {
            await this.loadExchangeRates();
        }

        console.log('💰 Currency display initialized:', {
            currency: this.userCurrency,
            hasRates: !!this.exchangeRates
        });
    }

    /**
     * Detect user's preferred currency
     */
    async detectUserCurrency() {
        try {
            // 1. Check if currency is already stored locally
            const storedCurrency = localStorage.getItem('userCurrency');
            if (storedCurrency && this.isValidCurrency(storedCurrency)) {
                this.userCurrency = storedCurrency;
                return;
            }

            // 2. Try to detect from server-side currency detection
            const response = await fetch('/.netlify/functions/detect-currency', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ detectOnly: true })
            });

            if (response.ok) {
                const data = await response.json();
                if (data.currency && this.isValidCurrency(data.currency)) {
                    this.userCurrency = data.currency;
                    localStorage.setItem('userCurrency', this.userCurrency);
                    return;
                }
            }
        } catch (error) {
            console.warn('Could not detect currency from server (normal in local dev):', error);
        }

        // 3. Fallback: try to detect from browser locale
        try {
            const locale = navigator.language || navigator.languages[0];
            const currencyFromLocale = this.getCurrencyFromLocale(locale);
            if (currencyFromLocale) {
                this.userCurrency = currencyFromLocale;
                localStorage.setItem('userCurrency', this.userCurrency);
                console.log('💰 Currency detected from browser locale:', this.userCurrency);
                return;
            }
        } catch (error) {
            console.warn('Could not detect currency from locale:', error);
        }

        // 4. For local development: simulate Canadian location if localhost
        if (window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1') {
            console.log('💰 Local development detected, defaulting to CAD for testing');
            this.userCurrency = 'CAD';
            localStorage.setItem('userCurrency', this.userCurrency);
        }
    }

    /**
     * Load exchange rates from server
     */
    async loadExchangeRates() {
        if (this.isLoading) return;

        this.isLoading = true;
        try {
            const response = await fetch('/.netlify/functions/get-exchange-rates', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ currency: this.userCurrency })
            });

            if (response.ok) {
                const data = await response.json();
                if (data.success && data.rates) {
                    this.exchangeRates = data.rates;
                    console.log('📈 Exchange rates loaded for', this.userCurrency);
                }
            }
        } catch (error) {
            console.warn('Could not load exchange rates:', error);
        } finally {
            this.isLoading = false;
        }
    }

    /**
     * Convert USD price to user's currency
     */
    convertPrice(usdPrice) {
        if (this.userCurrency === 'USD' || !this.exchangeRates) {
            return usdPrice;
        }

        const rate = this.exchangeRates[this.userCurrency];
        if (!rate) {
            console.warn('No exchange rate available for', this.userCurrency);
            return usdPrice;
        }

        return Math.round(usdPrice * rate);
    }

    /**
     * Format price with appropriate currency symbol and formatting
     */
    formatPrice(usdPrice, options = {}) {
        const convertedPrice = this.convertPrice(usdPrice);
        const currency = this.userCurrency;

        // Use native Intl.NumberFormat if available
        if (typeof Intl !== 'undefined' && Intl.NumberFormat) {
            try {
                const formatter = new Intl.NumberFormat(this.getLocaleForCurrency(currency), {
                    style: 'currency',
                    currency: currency,
                    minimumFractionDigits: 0,
                    maximumFractionDigits: 0
                });
                return formatter.format(convertedPrice);
            } catch (error) {
                console.warn('Intl.NumberFormat not available, using fallback');
            }
        }

        // Fallback formatting
        const symbol = this.fallbackSymbols[currency] || currency + ' ';
        return `${symbol}${convertedPrice}`;
    }

    /**
     * Update all price displays on the page
     */
    updateAllPrices() {
        // Update main product price
        const priceElements = document.querySelectorAll('.price, [data-price]');
        priceElements.forEach(element => {
            const usdPrice = parseFloat(element.dataset.usdPrice || element.textContent.replace(/[^\d.]/g, ''));
            if (usdPrice) {
                element.textContent = this.formatPrice(usdPrice);
                element.dataset.usdPrice = usdPrice; // Store original USD price
            }
        });

        // Update cart total if visible
        this.updateCartTotal();
    }

    /**
     * Update cart total with converted currency
     */
    updateCartTotal() {
        const cartTotalElement = document.getElementById('cart-total');
        if (cartTotalElement) {
            const cartItems = JSON.parse(localStorage.getItem('cartItems')) || [];
            const totalUSD = cartItems.reduce((sum, item) => {
                return sum + (parseFloat(item.price) * parseInt(item.quantity));
            }, 0);

            cartTotalElement.textContent = this.convertPrice(totalUSD).toFixed(2);
        }
    }

    /**
     * Update cart display when currency changes
     */
    updateCartDisplay() {
        // Trigger cart update if updateCartDisplay function exists globally
        if (typeof window.updateCartDisplay === 'function') {
            window.updateCartDisplay();
        }

        // Also update total
        this.updateCartTotal();
    }

    /**
     * Get locale string for currency formatting
     */
    getLocaleForCurrency(currency) {
        const localeMap = {
            'USD': 'en-US',
            'CAD': 'en-CA',
            'EUR': 'de-DE',
            'GBP': 'en-GB',
            'AUD': 'en-AU',
            'JPY': 'ja-JP',
            'CHF': 'de-CH',
            'SEK': 'sv-SE',
            'NOK': 'nb-NO',
            'DKK': 'da-DK'
        };
        return localeMap[currency] || 'en-US';
    }

    /**
     * Try to guess currency from browser locale
     */
    getCurrencyFromLocale(locale) {
        const localeCurrencyMap = {
            'en-CA': 'CAD',
            'fr-CA': 'CAD',
            'en-GB': 'GBP',
            'en-AU': 'AUD',
            'ja-JP': 'JPY',
            'de-DE': 'EUR',
            'fr-FR': 'EUR',
            'es-ES': 'EUR',
            'it-IT': 'EUR',
            'nl-NL': 'EUR',
            'sv-SE': 'SEK',
            'nb-NO': 'NOK',
            'da-DK': 'DKK',
            'de-CH': 'CHF'
        };

        // Check exact match first
        if (localeCurrencyMap[locale]) {
            return localeCurrencyMap[locale];
        }

        // Check language prefix
        const language = locale.split('-')[0];
        const languageCurrencyMap = {
            'de': 'EUR',
            'fr': 'EUR',
            'es': 'EUR',
            'it': 'EUR',
            'nl': 'EUR',
            'sv': 'SEK',
            'no': 'NOK',
            'da': 'DKK',
            'ja': 'JPY'
        };

        return languageCurrencyMap[language] || null;
    }

    /**
     * Check if currency code is valid
     */
    isValidCurrency(currency) {
        const validCurrencies = [
            'USD', 'CAD', 'EUR', 'GBP', 'AUD', 'JPY', 'CHF', 'SEK', 'NOK', 'DKK',
            'PLN', 'CZK', 'HUF', 'RON', 'BGN', 'HRK', 'RUB', 'TRY', 'BRL', 'MXN'
        ];
        return validCurrencies.includes(currency.toUpperCase());
    }

    /**
     * Set user currency (for currency switcher)
     */
    async setUserCurrency(currency) {
        if (!this.isValidCurrency(currency)) {
            console.error('Invalid currency:', currency);
            return false;
        }

        this.userCurrency = currency.toUpperCase();
        localStorage.setItem('userCurrency', this.userCurrency);

        // Load new exchange rates if needed
        if (this.userCurrency !== 'USD') {
            await this.loadExchangeRates();
        } else {
            this.exchangeRates = null;
        }

        // Update all prices on the page
        this.updateAllPrices();

        // Update cart display if cart is visible
        this.updateCartDisplay();

        console.log('💰 Currency changed to:', this.userCurrency);
        return true;
    }

    /**
     * Get current user currency
     */
    getUserCurrency() {
        return this.userCurrency;
    }

    /**
     * Get currency symbol
     */
    getCurrencySymbol() {
        return this.fallbackSymbols[this.userCurrency] || this.userCurrency + ' ';
    }
}

