    // Decide that "selectedSize" is the longer dimension. For example, if aspect ratio is 8:10
    // we treat "10" as the taller side. So if the user picks 20, we scale so that 10 -> 20,
    // width = 8*(20/10) = 16, height = 20. Then area = 16 * 20 = 320.
    // For 1:1 ratio, it become 20 × 20 = 400, as before.

    // We'll check if arW < arH (a "portrait" ratio). If so, treat selectedSize as arH. 
    // Otherwise, treat it as arW if arW > arH (a "landscape" ratio).
    let finalW, finalH;
    if (arW > arH) {
        // Landscape ratio
        finalW = selectedSize;
        finalH = Math.round(arH * (selectedSize / arW));
    } else {
        // Portrait or square ratio
        finalH = selectedSize;
        finalW = Math.round(arW * (selectedSize / arH));
    }
    const selectedArea = finalW * finalH;

    // Compare to base area for a 1:1 ratio with dimension = baseSize
    const baseArea = baseSize * baseSize;

    // area ratio
    const areaRatio = selectedArea / baseArea;

    // Take square root of area ratio to dampen the effect
    const dampedRatio = Math.sqrt(areaRatio);

    // Use the artwork's basePrice
    const price = isSignedEdition ? basePrice : basePrice / 2;
    const finalPrice = Math.round(price * dampedRatio);
    console.log('Calculated price:', finalPrice, 'selectedArea:', selectedArea);
    return { finalPrice, finalW, finalH };
}

function updatePrice() {
    const sizeSelect = document.getElementById('size-select');
    const editionSelect = document.getElementById('edition-select');
    const quantityInput = document.getElementById('quantity-input');
    const basePrice = parseFloat(document.querySelector('.product-details').dataset.basePrice);
    const aspectRatioStr = document.querySelector('.product-details').dataset.aspectRatio || '1:1';
    console.log('Update price basePrice:', basePrice, 'aspect ratio:', aspectRatioStr);

    const size = parseInt(sizeSelect.value);
    const isSignedEdition = editionSelect.value === 'signed';
    const quantity = parseInt(quantityInput.value) || 1;

    // 3. Adapt the call so it returns the computed width/height as well
    const { finalPrice, finalW, finalH } = calculatePrice(20, size, isSignedEdition, basePrice, aspectRatioStr);
    const totalPrice = finalPrice * quantity;

    // Use currency manager for proper formatting if available
    const priceElement = document.querySelector('.price');
    if (window.currencyManager) {
        priceElement.textContent = window.currencyManager.formatPrice(totalPrice);
        priceElement.dataset.usdPrice = totalPrice; // Store USD price for reference
    } else {
        priceElement.textContent = `$${totalPrice} USD`;
    }

    // Add sophisticated BNPL text
    const installmentAmount = Math.ceil(totalPrice / 4);
    let bnplElement = document.querySelector('.bnpl-installment-text');
    if (!bnplElement) {
        bnplElement = document.createElement('p');
        bnplElement.className = 'bnpl-installment-text';
        priceElement.parentNode.insertBefore(bnplElement, priceElement.nextSibling);
    }

    if (totalPrice >= 50) { // Only show BNPL for $50+
        if (window.currencyManager) {
            bnplElement.innerHTML = `<em>or acquire in 4 interest-free installments of ${window.currencyManager.formatPrice(installmentAmount)}</em>`;
        } else {
            bnplElement.innerHTML = `<em>or acquire in 4 interest-free installments of $${installmentAmount}</em>`;
        }
        bnplElement.style.display = 'block';
    } else {
        bnplElement.style.display = 'none';
    }

    // 4. Update the displayed "Actual Dimensions" text
    const dimsElem = document.getElementById('computed-dimensions');
    if (dimsElem) {
        dimsElem.textContent = `${finalW}" x ${finalH}" per print`;
    }

    // 5. Update BNPL messaging with new price
    updateBNPLMessaging();
}

// Pinterest Integration Functions
function updatePinterestMetadata(artwork) {
    const urlParams = new URLSearchParams(window.location.search);
    const artworkId = urlParams.get('id');
    const pageUrl = window.location.href;
    const imageUrl = new URL(artwork.src, window.location.origin).href;
    const title = `${artwork.title} | Edmund Dantes Studio`;
    const description = `${artwork.description || artwork.title} - Original geometric art print by Edmund Dantes Studio. Perfect for modern homes and offices. #geometricart #modernart #walldecor`;
    const price = artwork.basePrice || artwork.price || 350;

