import Stripe from 'stripe';
import { securityHeaders } from './utils/headers.js';
import { detectUserCurrency, getAvailableBNPLMethods } from './utils/currency-detection.js';
import { convertUSDToTargetCurrency } from './utils/exchange-rates.js';
import fs from 'fs';
import path from 'path';
import crypto from 'crypto';

const stripe = new Stripe(process.env.STRIPE_SECRET_KEY);

if (!process.env.STRIPE_SECRET_KEY) {
    throw new Error('STRIPE_SECRET_KEY is not set');
}

console.log('Stripe environment check:', {
    hasSecretKey: !!process.env.STRIPE_SECRET_KEY,
    secretKeyPattern: process.env.STRIPE_SECRET_KEY?.slice(0, 8),
    environment: process.env.NODE_ENV,
    url: process.env.URL
});

const requiredEnvVars = [
    'STRIPE_SECRET_KEY',
    'STRIPE_WEBHOOK_SECRET',
    'URL'
];

const missingVars = requiredEnvVars.filter(varName => !process.env[varName]);
if (missingVars.length > 0) {
    throw new Error(`Missing required environment variables: ${missingVars.join(', ')}`);
}

console.log('Environment check:', {
    hasSecretKey: !!process.env.STRIPE_SECRET_KEY,
    hasWebhookSecret: !!process.env.STRIPE_WEBHOOK_SECRET,
    hasURL: !!process.env.URL,
    environment: process.env.NODE_ENV
});

// Helper function to parse aspect ratio
function parseAspectRatio(aspectRatioStr) {
    const [rawW, rawH] = aspectRatioStr.split(':').map(Number);
    return { width: rawW || 1, height: rawH || 1 };
}

// Server-side price calculation - must match frontend logic exactly
function calculatePrice(baseSize, selectedSize, isSignedEdition, basePrice, aspectRatioStr) {
    const { width: arW, height: arH } = parseAspectRatio(aspectRatioStr);

    // Calculate dimensions based on longest side
    let finalW, finalH;
    if (arW > arH) {
        // Landscape ratio
        finalW = selectedSize;
        finalH = Math.round(arH * (selectedSize / arW));
    } else {
        // Portrait or square ratio
        finalH = selectedSize;
        finalW = Math.round(arW * (selectedSize / arH));
    }

    const selectedArea = finalW * finalH;
    const baseArea = baseSize * baseSize;
    const areaRatio = selectedArea / baseArea;
    const dampedRatio = Math.sqrt(areaRatio);

    // Apply edition pricing
    const price = isSignedEdition ? basePrice : basePrice / 2;
    const finalPrice = Math.round(price * dampedRatio);

    return { finalPrice, finalW, finalH };
}

// For now, we'll stick with USD only until we implement proper multi-currency
// This ensures BNPL works for US customers while we build the full solution

export const handler = async (event) => {
    if (event.httpMethod !== 'POST') {
        return {
            statusCode: 405,
            headers: securityHeaders,
            body: JSON.stringify({ error: 'Method not allowed' })
        };
    }

    try {
        console.log('Incoming request headers:', {
            'x-country': event.headers['x-country'],
            'x-nf-country': event.headers['x-nf-country'],
            'x-nf-geo': event.headers['x-nf-geo'],
            'referer': event.headers.referer
        });

        const { items, requestInstagramDiscount, sessionId, trafficSource, referrerUrl } = JSON.parse(event.body);
        if (!Array.isArray(items) || items.length === 0) {
            return {
                statusCode: 400,
                headers: securityHeaders,
                body: JSON.stringify({ error: 'Invalid items array' })
            };
        }

        // Load artwork data from secure server source
        const artworksData = await loadArtworksData();

        // Validate Instagram discount eligibility using secure cookie
        const isInstagramDiscountValid = requestInstagramDiscount && validateInstagramDiscount(event);

        // Validate items contain required fields
        const validItems = items.every(item => 
            item.id && 
            typeof item.quantity === 'number' && 
            item.quantity > 0 &&
            typeof item.size === 'number' &&
            item.size > 0 &&
            typeof item.isSignedEdition === 'boolean'
        );

        if (!validItems) {
            return {
                statusCode: 400,
                headers: securityHeaders,
                body: JSON.stringify({ error: 'Invalid item data - missing required fields (id, quantity, size, isSignedEdition)' })
            };
        }

        // Detect user's preferred currency
        const userCurrency = detectUserCurrency(event);

        // Build secure line items with server-authoritative pricing and currency conversion
        const secureLineItems = await buildSecureLineItems(items, artworksData, isInstagramDiscountValid, userCurrency);

        // Get available BNPL methods for this currency
        const availableBNPL = getAvailableBNPLMethods(userCurrency);

        console.log('Processing secure checkout:', {
            itemCount: items.length,
            instagramDiscount: isInstagramDiscountValid,
            sessionId: sessionId,
            totalAmount: secureLineItems.reduce((sum, item) => sum + (item.price_data.unit_amount * item.quantity), 0),
            currency: userCurrency,
            availableBNPL: availableBNPL,
            detectedCountry: event.headers['x-country'] || 'Unknown'
        });

        // Determine cancel URL - use referrer if provided, otherwise use referer header, fallback to home
        let cancelUrl = `${process.env.URL}/`;
        if (referrerUrl) {
            // Validate that referrer is from our domain
            try {
                const referrerUrlObj = new URL(referrerUrl);
                const ourUrlObj = new URL(process.env.URL);
                if (referrerUrlObj.hostname === ourUrlObj.hostname) {
                    cancelUrl = referrerUrl;
                }
            } catch (e) {
                console.warn('Invalid referrer URL:', referrerUrl);
            }
        } else if (event.headers.referer) {
            // Use referer header as fallback
            try {
                const refererUrlObj = new URL(event.headers.referer);
                const ourUrlObj = new URL(process.env.URL);
                if (refererUrlObj.hostname === ourUrlObj.hostname) {
                    cancelUrl = event.headers.referer;
                }
            } catch (e) {
                console.warn('Invalid referer header:', event.headers.referer);
            }
        }

        console.log('Using cancel URL:', cancelUrl);

        // Common session parameters
        const baseSessionParams = {
            line_items: secureLineItems,
            mode: 'payment',
            success_url: `${process.env.URL}/success.html?session_id={CHECKOUT_SESSION_ID}`,
            cancel_url: cancelUrl,
            billing_address_collection: 'required',
            shipping_address_collection: {
                allowed_countries: ['CA', 'US', 'AU', 'GB', 'FR', 'DE', 'NL', 'IT', 'ES', 'JP', 'SG'],
            },
            shipping_options: [
                {
                    shipping_rate_data: {
                        type: 'fixed_amount',
                        fixed_amount: { amount: 0, currency: userCurrency.toLowerCase() },
                        display_name: 'North America Shipping (US & Canada)',
                        delivery_estimate: {
                            minimum: { unit: 'business_day', value: 5 },
                            maximum: { unit: 'business_day', value: 7 }
                        }
                    }
                },
                {
                    shipping_rate_data: {
                        type: 'fixed_amount',
                        fixed_amount: { amount: 0, currency: userCurrency.toLowerCase() },
                        display_name: 'International Shipping',
                        delivery_estimate: {
                            minimum: { unit: 'business_day', value: 7 },
                            maximum: { unit: 'business_day', value: 21 }
                        }
                    }
                }
            ],
            custom_text: {
                shipping_address: {
                    message: 'Please note: Import duties, taxes, and customs fees are not included in the item price or shipping cost.'
                },
                submit: {
                    message: 'By placing this order, you agree to our terms of service.'
                }
            },
            consent_collection: {
                terms_of_service: 'required',
            }
        };

        let session;

        // Try automatic payment methods first (preferred approach)
        try {
            session = await stripe.checkout.sessions.create({
                ...baseSessionParams,
                automatic_payment_methods: {
                    enabled: true
                }
            });
            console.log('Successfully created session with automatic_payment_methods');
        } catch (automaticError) {
            // Check if it's the specific error about payment methods not being configured
            if (automaticError.type === 'StripeInvalidRequestError' && 
                (automaticError.message.includes('automatic_payment_methods') || 
                 automaticError.message.includes('payment method types'))) {

                console.warn(`
********************************************************************************
[Stripe Integration Warning]
Could not create Checkout Session with 'automatic_payment_methods'.
This is likely because payment methods are not enabled in your Stripe Dashboard.

Falling back to 'payment_method_types: ["card"]' for now.

ACTION REQUIRED: To enable modern payment methods like Klarna, Afterpay, etc.,
please visit your Stripe Dashboard and enable them here:
https://dashboard.stripe.com/test/settings/payment_methods
********************************************************************************
                `);

                // Fallback to explicit payment methods based on currency
                // Include BNPL methods that are available for this currency
                const paymentMethods = ['card'];

                // Add BNPL methods if available for this currency
                if (availableBNPL.includes('klarna')) paymentMethods.push('klarna');
                if (availableBNPL.includes('afterpay') || availableBNPL.includes('clearpay')) {
                    paymentMethods.push('afterpay_clearpay');
                }
                if (availableBNPL.includes('affirm')) paymentMethods.push('affirm');

                session = await stripe.checkout.sessions.create({
                    ...baseSessionParams,
                    payment_method_types: paymentMethods
                });
                console.log('Successfully created session with payment methods:', paymentMethods);
            } else {
                // Re-throw if it's a different error
                throw automaticError;
            }
        }

        console.log('Session created:', {
            id: session.id,
            url: session.url,
            status: session.status
        });

        return {
            statusCode: 200,
            headers: {
                ...securityHeaders,
                'Content-Type': 'application/json'
            },
            body: JSON.stringify({ 
                sessionId: session.id,
                publishableKey: process.env.STRIPE_PUBLISHABLE_KEY,
                currency: userCurrency,
                detectedCountry: event.headers['x-country'] || 'Unknown'
            })
        };
    } catch (error) {
        console.error('Checkout error:', {
            message: error.message,
            code: error.code,
            type: error.type,
            detail: error.detail,
            raw_type: error.raw?.type,
            decline_code: error.raw?.decline_code,
            stack: process.env.NODE_ENV === 'development' ? error.stack : undefined
        });

        return {
            statusCode: 500,
            headers: securityHeaders,
            body: JSON.stringify({ 
                error: process.env.NODE_ENV === 'development' ? error.message : 'Checkout failed',
                details: process.env.NODE_ENV === 'development' ? {
                    code: error.code,
                    type: error.type,
                    message: error.message
                } : undefined
            })
        };
    }
};

// Helper function to securely load artwork data
async function loadArtworksData() {
    try {
        // Use secure data location instead of public folder
        const artworksPath = path.join(process.cwd(), 'netlify', 'functions', 'data', 'artworks.json');
        const artworksContent = await fs.promises.readFile(artworksPath, 'utf8');
        const artworks = JSON.parse(artworksContent);

        // Create a lookup map for O(1) access
        const artworkMap = new Map();
        artworks.forEach(artwork => {
            artworkMap.set(artwork.id, artwork);
        });

        return artworkMap;
    } catch (error) {
        console.error('Failed to load artworks data:', error);
        throw new Error('Unable to load product catalog');
    }
}

// Helper function to validate Instagram discount eligibility using secure cookie
// Helper function to validate Instagram discount eligibility using signed cookie
function validateInstagramDiscount(event) {
    try {
        const cookieSecret = process.env.COOKIE_SECRET;
        if (!cookieSecret) {
            console.warn('COOKIE_SECRET not set - Instagram discount validation disabled');
            return false;
        }

        const cookies = event.headers.cookie || '';
        const cookieValue = cookies.split('instagram_discount_eligible=')[1]?.split(';')[0];

        if (!cookieValue) {
            return false;
        }

        const [value, signature] = cookieValue.split('.');
        if (!value || !signature) {
            console.warn('Malformed Instagram discount cookie');
            return false;
        }

        // Verify the HMAC signature
        const expectedSignature = crypto
            .createHmac('sha256', cookieSecret)
            .update(value)
            .digest('hex');

        // Use timingSafeEqual to prevent timing attacks
        const isValid = crypto.timingSafeEqual(
            Buffer.from(signature, 'hex'), 
            Buffer.from(expectedSignature, 'hex')
        );

        if (isValid && value === 'true') {
            console.log('✓ Valid Instagram discount cookie verified');
            return true;
        } else {
            console.warn('Invalid Instagram discount cookie signature');
            return false;
        }

    } catch (error) {
        console.warn('Error validating Instagram discount cookie:', error);
        return false;
    }
}

// Helper function to build secure Stripe line items with multi-currency support
async function buildSecureLineItems(items, artworkMap, isInstagramDiscountValid, targetCurrency = 'USD') {
    const lineItems = [];

    for (const item of items) {
        const artwork = artworkMap.get(item.id);

        if (!artwork) {
            throw new Error(`Artwork not found: ${item.id}`);
        }

        // Server-authoritative pricing calculation
        const basePriceUSD = parseFloat(artwork.basePrice);
        if (isNaN(basePriceUSD) || basePriceUSD <= 0) {
            throw new Error(`Invalid price for artwork: ${item.id}`);
        }

        // Calculate price based on size and edition
        const { finalPrice: calculatedPriceUSD, finalW, finalH } = calculatePrice(
            20, // base size (standard)
            item.size,
            item.isSignedEdition,
            basePriceUSD,
            artwork.aspectRatio || '1:1'
        );

        // Apply Instagram discount if validated
        const discountedPriceUSD = isInstagramDiscountValid ? 
            calculatedPriceUSD * 0.8 : // 20% off
            calculatedPriceUSD;

        // Convert to target currency (returns amount in smallest unit - cents, pence, etc.)
        const finalPriceInTargetCurrency = await convertUSDToTargetCurrency(discountedPriceUSD, targetCurrency);

        // Validate quantity
        const quantity = parseInt(item.quantity);
        if (isNaN(quantity) || quantity < 1 || quantity > 10) {
            throw new Error(`Invalid quantity for artwork: ${item.id}`);
        }

        const lineItem = {
            price_data: {
                currency: targetCurrency.toLowerCase(), // Stripe expects lowercase
                product_data: {
                    name: `${artwork.title} - ${item.size}" ${item.isSignedEdition ? 'Signed Edition' : 'Open Edition'}`,
                    description: `${artwork.description || 'Original artwork print'}\n\nDimensions: ${finalW}" × ${finalH}" (${item.size}" longest side)\nEdition: ${item.isSignedEdition ? 'Signed' : 'Open'}`,
                    images: artwork.src ? [`${process.env.URL}/${artwork.src}`] : [],
                    metadata: {
                        artwork_id: artwork.id,
                        title: artwork.title,
                        collection: artwork.collection,
                        size_inches: item.size.toString(),
                        dimensions: `${finalW}" × ${finalH}"`,
                        edition_type: item.isSignedEdition ? 'Signed' : 'Open',
                        aspect_ratio: artwork.aspectRatio || '1:1',
                        base_price_usd: basePriceUSD.toString(),
                        calculated_price_usd: calculatedPriceUSD.toString(),
                        instagram_discount: isInstagramDiscountValid.toString(),
                        discount_applied: isInstagramDiscountValid ? '20%' : '0%',
                        final_price_usd: discountedPriceUSD.toString(),
                        converted_from: 'USD'
                    }
                },
                unit_amount: finalPriceInTargetCurrency,
            },
            quantity: quantity,
        };

        lineItems.push(lineItem);
    }

    if (lineItems.length === 0) {
        throw new Error('No valid items to checkout');
    }

    console.log('Built secure line items:', {
        itemCount: lineItems.length,
        instagramDiscount: isInstagramDiscountValid,
        totalValue: lineItems.reduce((sum, item) => sum + (item.price_data.unit_amount * item.quantity), 0)
    });

    return lineItems;
}

